import{_ as o,C as l,o as r,c as i,a2 as e,E as s}from"./chunks/framework.e-meDy3u.js";const b=JSON.parse('{"title":"Q3 · 只用飞书 + AI + 脚本，7 天交付什么？","description":"","frontmatter":{},"headers":[],"relativePath":"q3.md","filePath":"q3.md"}'),n={name:"q3.md"};function p(d,a,c,_,h,q){const t=l("Timeline");return r(),i("div",null,[a[0]||(a[0]=e('<h1 id="q3-·-只用飞书-ai-脚本-7-天交付什么" tabindex="-1">Q3 · 只用飞书 + AI + 脚本，7 天交付什么？ <a class="header-anchor" href="#q3-·-只用飞书-ai-脚本-7-天交付什么" aria-label="Permalink to &quot;Q3 · 只用飞书 + AI + 脚本，7 天交付什么？&quot;">​</a></h1><p class="hqq-lede">七天不建平台，建一个能跑的闭环：Q2 那个第一版，摊成施工排期。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p><strong>七天不建平台，建一个能用的爆款素材库</strong>：装着真实赢家、AI 打好标签、告诉自家店这轮投哪条、收得回数据还能自动排名出日报。</p><p>全部就是 Q2 的两张飞书表，加上施工顺序。没有新工具，没有新概念。</p><hr><h2 id="七天排期" tabindex="-1">七天排期 <a class="header-anchor" href="#七天排期" aria-label="Permalink to &quot;七天排期&quot;">​</a></h2><p>每天产出什么看得见的东西，不按每天干什么活排。</p>',8)),s(t,{steps:[{label:"Day 1",title:"搭表 + 灌库 + 提权限申请",desc:"搭两张飞书表，把历史爆款素材灌进库（库开局不空），同时提交飞书写入权限审批。"},{label:"Day 2",title:"AI 打标签",desc:"AI 捷径给素材打标签：卖点、人群、场景，机器填人校对。"},{label:"Day 3",title:"分发回收表跑通",desc:"分发回收表跑通 + 投放视图，把素材真正用到自有私店。"},{label:"Day 4",title:"脚本写回",desc:"权限到位则启动：把 Excel 导出的回收数据批量写进表。",tag:"依赖权限审批"},{label:"Day 5",title:"自动排名视图 + 日报",desc:"库开始自己排名，直接指导追投。"},{label:"Day 6",title:"端到端真实数据跑通",desc:"用真实数据跑一遍完整链路，哪里断了修哪里。"},{label:"Day 7",title:"交付演示 + SOP",desc:"演示完整闭环，交付使用 SOP。",tag:"交付节点"}]}),a[1]||(a[1]=e('<hr><h2 id="衔接点-技术面原型的下一步" tabindex="-1">衔接点：技术面原型的下一步 <a class="header-anchor" href="#衔接点-技术面原型的下一步" aria-label="Permalink to &quot;衔接点：技术面原型的下一步&quot;">​</a></h2><p>技术面交的原型（<code>ai-eco-workflow</code>）干的是生产端：锁产品事实包 → 设实验变量 → 生成主图和详情页候选，带合规护栏。</p><p>它的下一步，我当时就规划好了，是把生成结果写进飞书素材库，让造出来的候选有地方沉淀、排名、复用。</p><p>所以这七天的交付，就是把那个&quot;下一步&quot;做出来：接上原型的出料口，在自家店把&quot;生产→库→投放→回收&quot;跑成闭环。</p><p>两段关系钉死：<strong>技术面原型 = 生产端（素材怎么造）；这周的库 = 出料口（造出来和赢过的素材存哪、怎么排名）。</strong></p><hr><h2 id="诚实边界" tabindex="-1">诚实边界 <a class="header-anchor" href="#诚实边界" aria-label="Permalink to &quot;诚实边界&quot;">​</a></h2><p>有一个不可控点，先说清楚：脚本自动写回依赖飞书写入权限审批（企业自建应用 bitable:app 权限），审批时间不在可控范围内。审批通过即自动，未通过则第七天先手动占坑，脚本第八九天补。</p><p>其余——两张表、灌库、AI 打标签、分发、排名视图——都是一周内确定能交出来的，不依赖任何外部审批。</p><p>原型目前是演示阶段，不是生产级。它证明的是这条链能跑通，不是明天就上量。这里不会把这个描述成&quot;明天上生产&quot;，但它也不是 PPT。</p>',11))])}const m=o(n,[["render",p]]);export{b as __pageData,m as default};
